SELECT COUNT(*) AS total_users, AVG(activity_goal) AS average_goal
FROM user_preferences
WHERE activity_goal IS NOT NULL;

SELECT user_id, COUNT(data_id) AS total_integrated_data
FROM integrated_data
GROUP BY user_id;

SELECT user_id, SUM(duration) AS total_activity_time
FROM activity_logs
GROUP BY user_id;

SELECT username
FROM users
WHERE height > (SELECT AVG(height) FROM users);

SELECT DISTINCT user_id
FROM devices
WHERE (JULIANDAY(DATE()) - JULIANDAY(registration_date)) > 30;

SELECT COUNT(DISTINCT activity_id) 
FROM activity_classifications
WHERE user_id = (SELECT user_id FROM users WHERE username = 'JohnDoe');

SELECT COUNT(*)
FROM sensor_readings
WHERE heart_rate > 100;

SELECT role, 100.0 * COUNT(*) / SUM(COUNT(*)) OVER () AS percentage
FROM users
GROUP BY role;

SELECT activity_id, AVG(calorie_burn_rate) AS Avg_Calorie_Burn_Rate
FROM activity_types
GROUP BY activity_id;
